    61→  response?: {
    62→    status?: number;
    63→    data?: {
    64→      message?: string;
    65→    };
    66→  };
    67→  message?: string;
    68→}
    69→
    70→const estados: string[] = [
    71→  "AC",
    72→  "AL",
    73→  "AP",
