    81→  "MT",
    82→  "MS",
    83→  "MG",
    84→  "PA",
    85→  "PB",
    86→  "PR",
    87→  "PE",
    88→  "PI",
    89→  "RJ",
    90→  "RN",
    91→  "RS",
    92→  "RO",
    93→  "RR",
    94→  "SC",
    95→  "SP",
    96→  "SE",
    97→  "TO",
    98→];
    99→
   100→export default function SalonDataPage() {
   101→  const { selectedSalon, updateSelectedSalon } = useSelectedSalon();
   102→  const { user } = useAuth();
   103→  const [isLoading, setIsLoading] = useState(false);
   104→  const [isSaving, setIsSaving] = useState(false);
   105→  const [isSearchingCEP, setIsSearchingCEP] = useState(false);
   106→  const [salonData, setSalonData] = useState<Salon | null>(null);
   107→  const [retryCount, setRetryCount] = useState(0);
   108→  const MAX_RETRIES = 3;
   109→
   110→  const navItems = getSalonNavItems(user?.role || "Profissional");
   111→
   112→  // Verifica se é modo de criação baseado na URL ou ausência de salão selecionado
   113→  const isCreateMode =
   114→    window.location.pathname.includes("/admin/") || !selectedSalon;
   115→  const isEditMode = !isCreateMode;
   116→
   117→  const [currentTab, setCurrentTab] = useState("informacoes");
   118→
   119→  const [salonInfo, setSalonInfo] = useState<SalonInfo>({
   120→    nomeFantasia: "",
   121→    razaoSocial: "",
   122→    cnpj: "",
   123→    telefoneComercial: "",
   124→    emailContato: "",
   125→    nomeLinkUtil: "",
   126→    urlLinkUtil: "",
   127→    timezone: "America/Sao_Paulo",
   128→  });
   129→
   130→  const [addressInfo, setAddressInfo] = useState<AddressInfo>({
   131→    cep: "",
   132→    rua: "",
   133→    numero: "",
   134→    complemento: "",
   135→    bairro: "",
   136→    cidade: "",
   137→    estado: "",
   138→  });
   139→
   140→  const [visualIdentity, setVisualIdentity] = useState<VisualIdentity>({
   141→    corPrincipal: "#ce4836",
   142→    logo: null,
   143→  });
   144→
   145→  // Fetch salon data on component mount
   146→  useEffect(() => {
   147→    const loadSalonData = async (): Promise<void> => {
   148→      if (isEditMode && selectedSalon?.id) {
   149→        await fetchSalonData();
   150→      }
   151→    };
   152→    loadSalonData();
   153→  }, [selectedSalon?.id, isEditMode]);
   154→
   155→  const fetchSalonData = async (): Promise<void> => {
   156→    if (!selectedSalon?.id) return;
   157→
   158→    setIsLoading(true);
   159→    try {
   160→      const data = await salonService.getById(selectedSalon.id);
   161→      setSalonData(data);
   162→
   163→      // Populate form fields with fetched data
   164→      setSalonInfo({
   165→        nomeFantasia: data.name || "",
   166→        razaoSocial: data.responsible || "",
   167→        cnpj: data.cnpj || "",
   168→        telefoneComercial: data.phone || "",
   169→        emailContato: data.email || "",
   170→        nomeLinkUtil: data.websiteName || "",
   171→        urlLinkUtil: data.websiteUrl || "",
   172→        timezone: data.timezone || "America/Sao_Paulo",
   173→      });
   174→
   175→      if (data.address) {
   176→        setAddressInfo({
   177→          cep: data.address.zipCode || "",
   178→          rua: data.address.street || "",
   179→          numero: data.address.number || "",
   180→          complemento: data.address.complement || "",
   181→          bairro: data.address.neighborhood || "",
   182→          cidade: data.address.city || "",
   183→          estado: data.address.state || "",
   184→        });
   185→      }
   186→
   187→      if (data.logo) {
   188→        setVisualIdentity((prev) => ({ ...prev, logo: data.logo || null }));
   189→      }
   190→
   191→      // Carregar cor primária do salão ou usar padrão
   192→      if (data.primaryColor) {
   193→        setVisualIdentity((prev) => ({
   194→          ...prev,
   195→          corPrincipal: data.primaryColor,
   196→        }));
   197→      } else {
   198→        // Usar cor padrão se não houver cor salva
   199→        setVisualIdentity((prev) => ({ ...prev, corPrincipal: "#ce4836" }));
   200→      }
   201→    } catch (error: unknown) {
   202→      const err = error as ErrorResponse;
   203→      toast.error("Algo deu errado. Tente novamente.");
   204→      setRetryCount(0);
   205→    } finally {
   206→      setIsLoading(false);
   207→    }
   208→  };
   209→
   210→  const handleSalonInfoChange = (
   211→    field: keyof SalonInfo,
   212→    value: string
   213→  ): void => {
   214→    setSalonInfo((prev) => ({ ...prev, [field]: value }));
   215→  };
   216→
   217→  const handleAddressChange = (
   218→    field: keyof AddressInfo,
   219→    value: string
   220→  ): void => {
   221→    setAddressInfo((prev) => ({ ...prev, [field]: value }));
   222→  };
   223→
   224→  const handleCEPChange = async (cep: string): Promise<void> => {
   225→    // Formatar CEP enquanto digita
   226→    const formattedCEP = cepService.formatCEP(cep);
   227→    handleAddressChange("cep", formattedCEP);
   228→
   229→    // Buscar endereço se CEP estiver completo (8 dígitos)
   230→    const cleanCEP = cep.replace(/\D/g, "");
   231→    if (cleanCEP.length === 8) {
   232→      setIsSearchingCEP(true);
   233→      try {
   234→        const addressData = await cepService.searchByCEP(cleanCEP);
   235→        if (addressData) {
   236→          setAddressInfo((prev) => ({
   237→            ...prev,
   238→            cep: formattedCEP,
   239→            rua: addressData.logradouro || prev.rua,
   240→            bairro: addressData.bairro || prev.bairro,
   241→            cidade: addressData.localidade || prev.cidade,
   242→            estado: addressData.uf || prev.estado,
   243→            complemento: addressData.complemento || prev.complemento,
   244→          }));
   245→          toast.success("Endereço encontrado e preenchido automaticamente!");
   246→        }
   247→      } catch (error: unknown) {
   248→        const err = error as ErrorResponse;
   249→        if (err.message === "CEP não encontrado") {
   250→          toast.error("CEP não encontrado. Verifique o número digitado.");
   251→        } else {
   252→          toast.error("Erro ao buscar endereço. Preencha manualmente.");
   253→        }
   254→      } finally {
   255→        setIsSearchingCEP(false);
   256→      }
   257→    }
   258→  };
   259→
   260→  const handleColorChange = (color: string): void => {
   261→    setVisualIdentity((prev) => ({ ...prev, corPrincipal: color }));
   262→  };
   263→
   264→  const handleLogoUpload = async (
   265→    event: React.ChangeEvent<HTMLInputElement>
   266→  ): Promise<void> => {
   267→    const file = event.target.files?.[0];
   268→    if (!file) return;
   269→
   270→    // Validate file size (max 5MB)
   271→    if (file.size > 5 * 1024 * 1024) {
   272→      toast.error("Arquivo muito grande. O tamanho máximo é 5MB");
   273→      event.target.value = ""; // Reset input
   274→      return;
   275→    }
   276→
   277→    // Validate file type
   278→    const allowedTypes = ["image/jpeg", "image/png", "image/webp"];
   279→    if (!allowedTypes.includes(file.type)) {
   280→      toast.error("Formato inválido. Use JPEG, PNG ou WebP");
   281→      event.target.value = ""; // Reset input
   282→      return;
   283→    }
   284→
   285→    if (!selectedSalon?.id) {
   286→      toast.error("Nenhum salão selecionado");
   287→      return;
   288→    }
   289→
   290→    // Store original logo for rollback
   291→    const originalLogo = visualIdentity.logo;
   292→
   293→    // Preview the image locally first
   294→    const reader = new FileReader();
   295→    reader.onload = (e) => {
   296→      setVisualIdentity((prev) => ({
   297→        ...prev,
   298→        logo: e.target?.result as string,
   299→      }));
   300→    };
   301→    reader.readAsDataURL(file);
   302→
   303→    // Upload to backend
   304→    try {
   305→      const response = await salonService.uploadLogo(selectedSalon.id, file);
   306→      toast.success("Logo enviada com sucesso!");
   307→      // Refresh data to get the updated logo URL from backend
   308→      await fetchSalonData();
   309→    } catch (error: unknown) {
   310→      const err = error as ErrorResponse;
   311→      toast.error("Algo deu errado. Tente novamente.");
   312→
   313→      // Rollback to original logo on error
   314→      setVisualIdentity((prev) => ({ ...prev, logo: originalLogo }));
   315→    } finally {
   316→      // Reset file input
   317→      event.target.value = "";
   318→    }
   319→  };
   320→
   321→  const validateForm = (): boolean => {
   322→    // Validate required fields
   323→    if (!salonInfo.nomeFantasia.trim()) {
   324→      toast.error("Nome fantasia é obrigatório");
   325→      setCurrentTab("informacoes");
   326→      return false;
   327→    }
   328→
   329→    if (!salonInfo.telefoneComercial.trim()) {
   330→      toast.error("WhatsApp é obrigatório");
   331→      setCurrentTab("informacoes");
   332→      return false;
   333→    }
   334→
   335→    // Validate email format if provided
   336→    if (salonInfo.emailContato) {
   337→      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   338→      if (!emailRegex.test(salonInfo.emailContato)) {
   339→        toast.error("E-mail inválido");
   340→        setCurrentTab("informacoes");
   341→        return false;
   342→      }
   343→    }
   344→
   345→    // Validate CNPJ if provided
   346→    if (salonInfo.cnpj) {
   347→      const cnpjClean = salonInfo.cnpj.replace(/[^\d]+/g, "");
   348→      if (cnpjClean.length > 0 && !salonService.validateCNPJ(cnpjClean)) {
   349→        toast.error("CNPJ inválido");
   350→        setCurrentTab("informacoes");
   351→        return false;
   352→      }
   353→    }
   354→
   355→    // Validate phone format
   356→    const phoneClean = salonInfo.telefoneComercial.replace(/[^\d]+/g, "");
   357→    if (phoneClean.length < 10 || phoneClean.length > 11) {
   358→      toast.error(
   359→        "Telefone inválido. Use o formato (XX) XXXXX-XXXX ou (XX) XXXX-XXXX"
   360→      );
   361→      setCurrentTab("informacoes");
   362→      return false;
   363→    }
   364→
   365→    // Validate address fields if any address field is filled
   366→    const hasAnyAddressField =
   367→      addressInfo.cep ||
   368→      addressInfo.rua ||
   369→      addressInfo.numero ||
   370→      addressInfo.bairro ||
   371→      addressInfo.cidade ||
   372→      addressInfo.estado;
   373→
   374→    if (hasAnyAddressField) {
   375→      if (!addressInfo.rua.trim()) {
   376→        toast.error("Rua é obrigatória no endereço");
   377→        setCurrentTab("endereco");
   378→        return false;
   379→      }
   380→      if (!addressInfo.numero.trim()) {
   381→        toast.error("Número é obrigatório no endereço");
   382→        setCurrentTab("endereco");
   383→        return false;
   384→      }
   385→      if (!addressInfo.bairro.trim()) {
   386→        toast.error("Bairro é obrigatório no endereço");
   387→        setCurrentTab("endereco");
   388→        return false;
   389→      }
   390→      if (!addressInfo.cidade.trim()) {
   391→        toast.error("Cidade é obrigatória no endereço");
   392→        setCurrentTab("endereco");
   393→        return false;
   394→      }
   395→      if (!addressInfo.estado.trim()) {
   396→        toast.error("Estado é obrigatório no endereço");
   397→        setCurrentTab("endereco");
   398→        return false;
   399→      }
   400→
   401→      // Validate CEP format
   402→      const cepClean = addressInfo.cep.replace(/[^\d]+/g, "");
   403→      if (cepClean.length > 0 && cepClean.length !== 8) {
   404→        toast.error("CEP inválido. Use o formato XXXXX-XXX");
   405→        setCurrentTab("endereco");
   406→        return false;
   407→      }
   408→    }
   409→
   410→    // Validate URL if provided
   411→    if (salonInfo.urlLinkUtil) {
   412→      try {
   413→        new URL(salonInfo.urlLinkUtil);
   414→      } catch {
   415→        toast.error("URL inválida. Use o formato https://exemplo.com");
   416→        setCurrentTab("informacoes");
   417→        return false;
   418→      }
   419→    }
   420→
   421→    return true;
   422→  };
   423→
   424→  const handleSave = async (): Promise<void> => {
   425→    // Run validation first
   426→    if (!validateForm()) {
   427→      return;
   428→    }
   429→
   430→    if (isCreateMode) {
   431→      // TODO: Implement creation logic when needed
   432→      toast.success("Salão criado com sucesso!");
   433→    } else {
   434→      if (!selectedSalon?.id) {
   435→        toast.error("Nenhum salão selecionado");
   436→        return;
   437→      }
   438→
   439→      setIsSaving(true);
   440→      try {
   441→        const updateData: UpdateSalonDto = {
   442→          name: salonInfo.nomeFantasia.trim(),
   443→          responsible: salonInfo.razaoSocial.trim() || undefined,
   444→          cnpj: salonInfo.cnpj.trim() || undefined,
   445→          phone: salonInfo.telefoneComercial.trim(),
   446→          email: salonInfo.emailContato.trim() || undefined,
   447→          primaryColor: visualIdentity.corPrincipal,
   448→          websiteName: salonInfo.nomeLinkUtil.trim() || undefined,
   449→          websiteUrl: salonInfo.urlLinkUtil.trim() || undefined,
   450→          timezone: salonInfo.timezone,
   451→          // Explicitly handle logo - set to null if removed, otherwise keep current
   452→          logo:
   453→            visualIdentity.logo === null
   454→              ? null
   455→              : visualIdentity.logo || undefined,
   456→        };
   457→
   458→        // Only add address if at least one field is filled
   459→        const hasAnyAddressField =
   460→          addressInfo.cep ||
   461→          addressInfo.rua ||
   462→          addressInfo.numero ||
   463→          addressInfo.bairro ||
   464→          addressInfo.cidade ||
   465→          addressInfo.estado;
   466→
   467→        if (hasAnyAddressField) {
   468→          updateData.address = {
   469→            zipCode: addressInfo.cep.trim(),
   470→            street: addressInfo.rua.trim(),
   471→            number: addressInfo.numero.trim(),
   472→            complement: addressInfo.complemento.trim() || undefined,
   473→            neighborhood: addressInfo.bairro.trim(),
   474→            city: addressInfo.cidade.trim(),
   475→            state: addressInfo.estado.trim(),
   476→            country: "Brasil",
   477→          };
   478→        }
   479→
   480→        const updatedSalon = await salonService.update(
   481→          selectedSalon.id,
   482→          updateData
   483→        );
   484→
   485→        toast.success("Alterações salvas com sucesso!");
   486→
   487→        trackSeverinoEvent('alteracao_dados_do_salao', {
   488→          description: `Dados do salão alterados: ${salonInfo.nomeFantasia}`,
   489→          salonId: selectedSalon.id
   490→        });
   491→
   492→        // Update the selected salon in the hook to refresh the UI
   493→        if (updateSelectedSalon) {
   494→          updateSelectedSalon(updatedSalon);
   495→        }
   496→
   497→        // Refresh the data after saving
   498→        await fetchSalonData();
   499→      } catch (error: unknown) {
   500→        const err = error as ErrorResponse;
   501→
   502→        if (err.response?.data?.message) {
   503→          toast.error(err.response.data.message);
   504→        } else if (err.message) {
   505→          toast.error(err.message);
   506→        } else {
   507→          toast.error("Erro ao salvar alterações. Tente novamente.");
   508→        }
   509→      } finally {
   510→        setIsSaving(false);
   511→      }
   512→    }
   513→  };
   514→
   515→  const handleNext = (): void => {
   516→    // Validate current tab before moving to next
   517→    if (currentTab === "informacoes") {
   518→      if (!salonInfo.nomeFantasia.trim()) {
   519→        toast.error("Preencha o nome fantasia antes de continuar");
   520→        return;
   521→      }
   522→      if (!salonInfo.telefoneComercial.trim()) {
   523→        toast.error("Preencha o WhatsApp antes de continuar");
   524→        return;
   525→      }
   526→      setCurrentTab("endereco");
   527→    } else if (currentTab === "endereco") {
   528→      setCurrentTab("identidade");
   529→    }
   530→  };
   531→
   532→  const isLastTab = currentTab === "identidade";
   533→
   534→  const getContrastColor = (hexColor: string): string => {
   535→    const hex = hexColor.replace("#", "");
   536→    const r = parseInt(hex.substr(0, 2), 16);
   537→    const g = parseInt(hex.substr(2, 2), 16);
   538→    const b = parseInt(hex.substr(4, 2), 16);
   539→    const brightness = (r * 299 + g * 587 + b * 114) / 1000;
   540→    return brightness > 128 ? "#000000" : "#ffffff";
   541→  };
   542→
   543→  const formatUrlSlug = (text: string): string => {
   544→    return text
   545→      .toLowerCase()
   546→      .normalize("NFD")
   547→      .replace(/[\u0300-\u036f]/g, "") // Remove acentos
   548→      .replace(/[^a-z0-9\s-]/g, "") // Remove caracteres especiais
   549→      .trim()
   550→      .replace(/\s+/g, "-"); // Substitui espaços por hífens
   551→  };
   552→
   553→  return (
   554→    <EasySalonLayout
   555→      sideNavTitle="Easy Salon"
   556→      sideNavSubtitle={selectedSalon?.name || "Salão"}
   557→      sideNavItems={navItems}
   558→    >
   559→      <PageHeader
   560→        title={isCreateMode ? "Cadastrar Novo Salão" : "Editar Dados do Salão"}
   561→        subtitle="Gerencie as informações do seu salão"
   562→        disabledActions={!selectedSalon?.active}
   563→      />
   564→
   565→      {isLoading && retryCount === 0 ? (
   566→        <div className="bg-card border border-border rounded-3xl">
   567→          <div className="p-6">
   568→            <div className="flex items-center justify-center py-12">
   569→              <Loader2 className="h-8 w-8 animate-spin text-[#dd4227]" />
   570→              <span className="ml-2">Carregando dados do salão...</span>
   571→            </div>
   572→          </div>
   573→        </div>
   574→      ) : (
   575→        <div className="bg-card border border-border rounded-3xl">
   576→          <div className="p-6">
   577→            <Tabs
   578→              value={currentTab}
   579→              onValueChange={setCurrentTab}
   580→              className="w-full"
   581→            >
   582→              <TabsList className="grid w-full grid-cols-3 mb-6 h-auto gap-1 p-1">
   583→                <TabsTrigger
   584→                  value="informacoes"
   585→                  className="text-xs py-2 px-1 leading-tight text-center whitespace-normal data-[state=active]:text-[#ce4836] data-[state=active]:border-b-2 data-[state=active]:border-[#ce4836]"
   586→                >
   587→                  Informações do Salão
   588→                </TabsTrigger>
   589→                <TabsTrigger
   590→                  value="endereco"
   591→                  className="text-xs py-2 px-1 leading-tight text-center whitespace-normal data-[state=active]:text-[#ce4836] data-[state=active]:border-b-2 data-[state=active]:border-[#ce4836]"
   592→                >
   593→                  Endereço Comercial
   594→                </TabsTrigger>
   595→                <TabsTrigger
   596→                  value="identidade"
   597→                  className="text-xs py-2 px-1 leading-tight text-center whitespace-normal data-[state=active]:text-[#ce4836] data-[state=active]:border-b-2 data-[state=active]:border-[#ce4836]"
   598→                >
   599→                  Identidade Visual
   600→                </TabsTrigger>
   601→              </TabsList>
   602→
   603→              <TabsContent value="informacoes" className="space-y-6">
   604→                <TooltipProvider>
