    86→// Helper para converter string yyyy-MM-dd em objeto Date local sem problemas de timezone
    87→const parseLocalDate = (dateStr: string): Date | null => {
    88→  if (!dateStr) return null;
    89→  const [year, month, day] = dateStr.split("-").map(Number);
    90→  if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
    91→  return new Date(year, month - 1, day);
    92→};
