    21→export function ChangePlanModal({ isOpen, onClose, onConfirm, currentPlanId, plans }: ChangePlanModalProps) {
    22→    const [selectedId, setSelectedId] = useState<string>(currentPlanId || "");
    23→    const [isSubmitting, setIsSubmitting] = useState(false);
    24→
    25→    useEffect(() => {
    26→        if (currentPlanId) {
    27→            setSelectedId(currentPlanId);
    28→        } else if (plans.length > 0 && !selectedId) {
    29→            setSelectedId(plans[0].id);
    30→        }
    31→    }, [currentPlanId, plans]);
    32→
    33→    const selectedPlan = plans.find(p => p.id === selectedId);
    34→    const isConsultation = selectedPlan?.consultationRequired;
    35→
    36→    const handleConfirm = async () => {
    37→        if (isConsultation) {
    38→            const phoneNumber = import.meta.env.VITE_WHATSAPP_COMERCIAL || "5541985290866";
    39→            const message = `Olá! Tenho interesse no plano ${selectedPlan.name} do Easy Salon. Poderia me passar mais informações?`;
