    41→            onClose();
    42→            return;
    43→        }
    44→
    45→        setIsSubmitting(true);
    46→        try {
    47→            await onConfirm(selectedId);
    48→            onClose();
    49→        } finally {
    50→            setIsSubmitting(false);
    51→        }
    52→    };
    53→
    54→    return (
    55→        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
    56→            <DialogContent className="w-[95vw] md:max-w-[500px] max-h-[90vh] md:max-h-[85vh] p-0 gap-0 rounded-xl md:rounded-lg border-none shadow-2xl overflow-hidden flex flex-col">
