    68→                            const isPlanConsultation = plan.consultationRequired;
    69→                            const price = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(plan.amount);
    70→
    71→                            return (
    72→                                <div
    73→                                    key={plan.id}
    74→                                    onClick={() => setSelectedId(plan.id)}
    75→                                    className={cn(
