    77→                                        isPlanSelected
    78→                                            ? "border-[#dd4227] bg-[#dd4227]/5"
    79→                                            : "border-border hover:border-muted-foreground/30"
    80→                                    )}
    81→                                >
    82→                                    <div className="flex justify-between items-start mb-2">
    83→                                        <h3 className="text-lg font-bold text-foreground">{plan.name}</h3>
    84→                                        {isPlanConsultation ? (
    85→                                            <div className="flex items-center gap-1 px-2 py-1 bg-primary/10 rounded text-[10px] uppercase font-bold text-primary">
    86→                                                <MessageCircle className="w-3 h-3" />
    87→                                                Sob Consulta
    88→                                            </div>
    89→                                        ) : isPlanSelected && (
    90→                                            <div className="bg-[#dd4227] rounded-full p-1">
    91→                                                <Check className="w-4 h-4 text-white" />
    92→                                            </div>
    93→                                        )}
    94→                                    </div>
    95→
    96→                                    <p className="text-sm text-muted-foreground mb-4 pr-8">
    97→                                        {plan.description}
    98→                                    </p>
    99→
   100→                                    <div className="flex items-baseline gap-1">
   101→                                        <span className={cn(
   102→                                            "text-2xl font-bold",
   103→                                            isPlanConsultation ? "text-primary/70" : "text-[#dd4227]"
   104→                                        )}>
   105→                                            {isPlanConsultation ? "Sob Consulta" : price}
   106→                                        </span>
   107→                                        {!isPlanConsultation && <span className="text-sm text-muted-foreground">/mês</span>}
   108→                                    </div>
   109→                                </div>
   110→                            );
   111→                        })}
   112→                    </div>
   113→                </div>
   114→
   115→                <div className="sticky bottom-0 z-10 bg-background px-4 pt-3 pb-4 border-t shrink-0 flex flex-col-reverse sm:flex-row sm:justify-end gap-2 sm:gap-3">
   116→                    <Button
