   123→                    </Button>
   124→                    <Button
   125→                        className="w-full sm:flex-1 h-12 rounded-xl bg-[#dd4227] hover:bg-[#dd4227]/90 text-white font-semibold border-none min-h-[44px]"
   126→                        onClick={handleConfirm}
   127→                        disabled={isSubmitting || !selectedId}
   128→                    >
   129→                        {isSubmitting ? <RefreshCw className="w-4 h-4 animate-spin mr-2" /> : null}
   130→                        {isConsultation ? "Falar com Consultor" : "Confirmar alteração"}
   131→                    </Button>
