    97→// Função de busca inteligente que ignora case, acentos e permite busca parcial
    98→const normalizeString = (str: string): string => {
    99→  return str
   100→    .toLowerCase()
   101→    .normalize("NFD")
   102→    .replace(/[\u0300-\u036f]/g, "") // Remove acentos
   103→    .replace(/[^a-z0-9\s]/g, ""); // Remove caracteres especiais
   104→};
   105→
   106→// Função de busca flexível que funciona com diferentes formatos de texto
   107→const smartSearch = (searchTerm: string, target: string): boolean => {
   108→  if (!searchTerm || !target) return true;
   109→
   110→  const normalizedSearch = normalizeString(searchTerm);
   111→  const normalizedTarget = normalizeString(target);
   112→
   113→  // Busca exata
   114→  if (normalizedTarget.includes(normalizedSearch)) {
   115→    return true;
   116→  }
   117→
   118→  // Busca por palavras separadas (permite buscar "jo si" para encontrar "João Silva")
   119→  const searchWords = normalizedSearch
   120→    .split(/\s+/)
   121→    .filter((word) => word.length > 0);
   122→  return searchWords.every((word) => normalizedTarget.includes(word));
   123→};
