   610→  const generateTimeSlots = (
   611→    startHour: string,
   612→    endHour: string,
   613→    interval: number = 15
   614→  ): string[] => {
   615→    const slots: string[] = [];
   616→    const [startH, startM] = startHour.split(":").map(Number);
   617→    const [endH, endM] = endHour.split(":").map(Number);
   618→
   619→    const startMinutes = startH * 60 + startM;
   620→    const endMinutes = endH * 60 + endM;
   621→
   622→    for (
   623→      let minutes = startMinutes;
   624→      minutes < endMinutes;
   625→      minutes += interval
   626→    ) {
   627→      const hours = Math.floor(minutes / 60);
   628→      const mins = minutes % 60;
   629→      slots.push(
   630→        `${hours.toString().padStart(2, "0")}:${mins
   631→          .toString()
   632→          .padStart(2, "0")}`
   633→      );
   634→    }
   635→
   636→    return slots;
   637→  };
