    57→const ACTIONS_COLUMN_KEY = "__actions__";
    58→
    59→function buildActionsColumn<T>(actions: TableAction<T>[]): Column<T> {
    60→  return {
    61→    key: ACTIONS_COLUMN_KEY,
    62→    header: "Ações",
    63→    width: "1%",
    64→    className: "text-right",
    65→    render: (_: unknown, row: T): React.ReactNode => (
    66→      <div className="flex items-center justify-end gap-1">
    67→        {actions.map((action, i) => {
    68→          if (action.hidden?.(row)) return null;
    69→          return (
    70→            <Button
    71→              key={i}
    72→              variant="ghost"
    73→              size="icon"
    74→              onClick={(e: React.MouseEvent) => {
