    84→              title={action.label}
    85→            >
    86→              {action.icon}
    87→            </Button>
    88→          );
    89→        })}
    90→      </div>
    91→    ),
    92→  };
    93→}
    94→
    95→export function DataTable<T extends object>({
    96→  data,
    97→  columns,
    98→  actions,
    99→  onRowClick,
   100→  className,
