   181→                  )}
   182→                </div>
   183→                {mobileCardConfig?.badge && (
   184→                  <span className="bg-secondary text-primary text-[10px] font-bold uppercase px-2 py-0.5 rounded-full">
   185→                    {getMobileValue(row, mobileCardConfig.badge)}
   186→                  </span>
