   763→
   764→                  {/* Grade de horários - só mostra se data e profissional selecionados */}
   765→                  {selectedDate &&
   766→                  selectedProfessionalId &&
   767→                  availabilityData?.slots ? (
   768→                    <div className="space-y-4">
   769→                      {availabilityData.slots &&
   770→                      availabilityData.slots.length > 0 ? (
   771→                        <div className="border rounded-lg p-3">
