   776→                              {
   777→                                availabilityData.slots.filter(
   778→                                  (s: any) => s.available
   779→                                ).length
   780→                              }{" "}
   781→                              livres de {availabilityData.slots.length}
   782→                            </Badge>
   783→                          </h4>
   784→
   785→                          <div className="grid grid-cols-4 sm:grid-cols-5 md:grid-cols-6 lg:grid-cols-4 gap-2"> {/* RESP: Grid mais flexível */}
   786→                            {availabilityData.slots.map(
   787→                              (slot: any, index: number) => {
   788→                                const now = new Date();
   789→                                const isToday =
   790→                                  format(selectedDate, "yyyy-MM-dd") ===
   791→                                  format(now, "yyyy-MM-dd");
   792→                                const currentTime = format(now, "HH:mm");
   793→                                const isPast = isToday && slot.time < currentTime;
   794→                                const isAvailable = slot.available && !isPast;
   795→
   796→                                return (
   797→                                  <div
   798→                                    key={index}
   799→                                    className={cn(
   800→                                      "p-2 rounded text-[10px] md:text-xs text-center transition-colors font-medium border", /* RESP: Adicionada borda */
   801→                                      isAvailable
