   803→                                        : isPast
   804→                                        ? "bg-muted text-muted-foreground border-transparent cursor-not-allowed opacity-50"
   805→                                        : slot.reason === "appointment"
   806→                                        ? "bg-red-50 text-red-800 border-red-200 cursor-not-allowed opacity-75"
   807→                                        : slot.reason === "break"
   808→                                        ? "bg-yellow-50 text-yellow-800 border-yellow-200 cursor-not-allowed opacity-75"
   809→                                        : slot.reason === "absence"
   810→                                        ? "bg-purple-50 text-purple-800 border-purple-200 cursor-not-allowed opacity-75"
   811→                                        : slot.reason === "non-working"
   812→                                        ? "bg-muted/30 text-muted-foreground border-border cursor-not-allowed opacity-75"
   813→                                        : slot.reason === "insufficient-duration"
   814→                                        ? "bg-orange-50 text-orange-800 border-orange-200 cursor-not-allowed opacity-75"
   815→                                        : "bg-muted text-muted-foreground border-border cursor-not-allowed opacity-75",
   816→                                      selectedTime === slot.time &&
   817→                                        "ring-2 ring-primary border-transparent"
   818→                                    )}
   819→                                    onClick={() => {
   820→                                      if (isAvailable) {
   821→                                        setSelectedTime(slot.time);
   822→                                      }
   823→                                    }}
   824→                                    title={
   825→                                      isPast
   826→                                        ? "Horário já passou"
   827→                                        : !slot.available
   828→                                        ? slot.reason === "appointment"
   829→                                          ? "Horário ocupado"
   830→                                          : slot.reason === "break"
   831→                                          ? "Horário de intervalo"
   832→                                          : slot.reason === "absence"
   833→                                          ? "Profissional ausente"
   834→                                          : slot.reason === "non-working"
   835→                                          ? "Fora do horário de trabalho"
   836→                                          : slot.reason ===
   837→                                            "insufficient-duration"
   838→                                          ? "Tempo insuficiente"
   839→                                          : "Horário indisponível"
   840→                                        : "Horário disponível"
   841→                                    }
   842→                                  >
   843→                                    <div className="font-bold">{slot.time}</div>
   844→                                  </div>
   845→                                );
   846→                              }
   847→                            )}
   848→                          </div>
   849→                        </div>
   850→                      ) : (
   851→                        <div className="text-center py-4 text-muted-foreground text-xs font-medium">
   852→                          <p>Nenhum horário disponível para esta data</p>
   853→                        </div>
   854→                      )}
   855→                    </div>
   856→                  ) : selectedDate && loadingAvailability ? (
   857→                    <div className="text-center py-8 text-muted-foreground">
   858→                      <Clock className="h-10 w-10 mx-auto mb-2 opacity-50 animate-spin" />
   859→                      <p className="text-xs">Carregando horários...</p>
